# Let's just manually validate the YAML by checking key structures
with open('/home/runner/work/rlm-action/rlm-action/.github/workflows/issue-processor.yml', 'r') as f:
    content = f.read()

# Check for common YAML issues
issues = []

# Check for tabs (YAML should use spaces)
if '\t' in content:
    issues.append("File contains tabs - YAML should use spaces")

# Check basic structure
if 'name: rlm-issue-processor' not in content:
    issues.append("Missing workflow name")
if 'on:' not in content:
    issues.append("Missing 'on' trigger")
if 'jobs:' not in content:
    issues.append("Missing 'jobs' section")
if 'process-issue:' not in content:
    issues.append("Missing process-issue job")
if 'uses: actions/github-script@v7' not in content:
    issues.append("Missing github-script usage")

# Check for our new step
if 'Post comment when no changes' not in content:
    issues.append("Missing 'Post comment when no changes' step")
if 'issues.createComment' not in content:
    issues.append("Missing createComment call")

# Check permissions
if 'issues: write' not in content:
    issues.append("Missing 'issues: write' permission")

if issues:
    print("Issues found:")
    for issue in issues:
        print(f"  - {issue}")
else:
    print("All basic validations passed!")

